students = {}

def add_student(name):
    if name in students:
        return False
    students[name] = {'grades': [], 'attendance': 0, 'total_classes': 0}
    return True

def add_grade(name, subject, score):
    if name not in students:
        return False
    if score < 0 or score > 100:
        return False
    students[name]['grades'].append({'subject': subject, 'score': score})
    return True

def get_average(name):
    if name not in students:
        return -1
    if len(students[name]['grades']) == 0:
        return 0
    total = 0
    for g in students[name]['grades']:
        total = total + g['score']
    return total / len(students[name]['grades'])

def get_letter_grade(name):
    avg = get_average(name)
    if avg == -1:
        return 'N/A'
    if avg >= 90:
        return 'A'
    if avg >= 80:
        return 'B'
    if avg >= 70:
        return 'C'
    if avg >= 60:
        return 'D'
    return 'F'

def record_attendance(name, present):
    if name not in students:
        return False
    students[name]['total_classes'] = students[name]['total_classes'] + 1
    if present:
        students[name]['attendance'] = students[name]['attendance'] + 1
    return True

def get_attendance_rate(name):
    if name not in students:
        return -1
    if students[name]['total_classes'] == 0:
        return 0
    return students[name]['attendance'] / students[name]['total_classes']

def get_report(name):
    if name not in students:
        return None
    return {
        'name': name,
        'average': get_average(name),
        'letter_grade': get_letter_grade(name),
        'attendance_rate': get_attendance_rate(name),
        'total_grades': len(students[name]['grades'])
    }
